+/// Default breakpoint boundary widths for testing.
+/// Each pair is (just_below, at_threshold) for each breakpoint.
+const BOUNDARY_WIDTHS: [(u16, u16); 4] = [
+    (59, 60),   // Sm boundary
+    (89, 90),   // Md boundary
+    (119, 120), // Lg boundary
+    (159, 160), // Xl boundary
+];
