+
+fn two_column() -> Flex {
+    Flex::horizontal().constraints([Constraint::Fixed(30), Constraint::Fill])
+}
+
+fn three_column() -> Flex {
+    Flex::horizontal().constraints([
+        Constraint::Fixed(25),
+        Constraint::Fill,
+        Constraint::Fixed(25),
